def main(arg1: list,arg3: str) -> dict:
    if '无' in arg3:
        return {
            "车型": "无",
            "车系": "无"
        }
    series_map = {
      "电自E系列": "E",
      "电自F系列": "F",
      "电自M系列": "M",
      "电自N系列": "N",
      "电自Nz系列": "Nz",
      "电动E系列": "E",
      "电动F系列": "F",
      "电动M系列": "M", 
      "电动N系列": "N",
      "电动Nz系列": "Nz"
    }
    if arg1 and len(arg1)>0:
        json_data = arg1[0]
        vehicle_model = json_data.get('ebike_车型名称', '')
        vehicle_series = json_data.get('ebike_车系名称', '')
        type = json_data.get('ebike_类型', '')
        if vehicle_model:
            return {
                  "车型": vehicle_model,
                  "车系": series_map.get(vehicle_series, '无')
                }
    return {
        "车型": "无",
        "车系": "无"
    }
